dashboard.definition:
{
  "title": "Details",
  "visualizations": {
    "viz_node_details_0": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_node_details_0"
      },
      "title": "NVE VNIs ▲ Up / ▼ Down",
      "description": "Single card showing the latest-snapshot count of operationally Up (▲) and Down (▼) NVE VNIs (cisco.vni-oper-state_info, nve-vni-oper) aggregated across every node in the selected role.\n\nA non-zero ▼ Down count flags a VNI gone operationally down (e.g. an L3VNI core SVI shut).",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_node_details_1": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_node_details_1"
      },
      "title": "BGP Sessions ▲ Up / ▼ Down",
      "description": "Single card showing the latest-snapshot count of BGP sessions that are Up (▲, negotiated hold-time > 0) and Down (▼, hold-time = 0) across every node in the selected role.\n\nA non-zero ▼ Down count flags one or more BGP neighbors not Established.",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_node_details_2": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_node_details_2"
      },
      "title": "VTEP Tunnel Peers",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_node_details_3": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_node_details_3"
      },
      "title": "Active L2 VNIs",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_node_details_4": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_node_details_4"
      },
      "title": "Active VRFs / L3 VNIs",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_node_details_5": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_node_details_5"
      },
      "title": "Silent Nodes (>5m)",
      "description": "Inventory-seeded count of nodes in the selected role with no periodic telemetry heartbeat in the last 5 minutes from any critical subscription path (NVE oper, NVE peer adjacency, or interface oper-state). On-change BGP alone does not keep a node \"alive\".",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off",
        "backgroundColor": "> primary | seriesByIndex(0) | lastPoint() | rangeValue(singleValueColorConfig)"
      },
      "context": {
        "singleValueColorConfig": [
          {
            "to": 1,
            "value": "#53A051"
          },
          {
            "from": 1,
            "value": "#DC4E41"
          }
        ]
      }
    },
    "viz_node_details_21": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_node_details_21"
      },
      "title": "Tunnel Interfaces ▲ Up / ▼ Down",
      "description": "Latest-snapshot count of operationally Up (▲, if-oper-state-ready) and Down (▼) Tunnel* interfaces (cisco.oper-status_info, Sub 40120/40121) across every node in the selected role.\n\nA non-zero ▼ Down count flags an underlay /overlay tunnel interface down on that node.",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_node_details_6": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_node_details_6"
      },
      "title": "BGP Established Sessions per Node",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Sessions",
        "yAxisMajorTickInterval": 1,
        "showYAxisWithZero": true,
        "nullValueDisplay": "connect"
      }
    },
    "viz_node_details_7": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_node_details_7"
      },
      "title": "L3 VNI (VRF) Count per Node",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "VNI Count",
        "nullValueDisplay": "connect"
      }
    },
    "viz_node_details_8": {
      "type": "splunk.table",
      "dataSources": {
        "primary": "ds_node_details_8"
      },
      "title": "BGP EVPN Session State",
      "description": "Device × peer matrix for BGP sessions in the default/global VRF (fabric EVPN overlay control plane). 🟢 = all sessions Established for that pair; 🔴 = any session down.\n\nWorst-case across all default-VRF neighbor contexts.",
      "options": {}
    },
    "viz_node_details_23": {
      "type": "splunk.table",
      "dataSources": {
        "primary": "ds_node_details_23"
      },
      "title": "BGP IPv4 Session State",
      "description": "Device × peer matrix for BGP sessions in tenant (non-default) VRFs — vpnv4-unicast / L3 handoff. 🟢 = all sessions Established for that pair; 🔴 = any session down.\n\nExternal peers not in the inventory appear by neighbor IP.",
      "options": {}
    },
    "viz_node_details_22": {
      "type": "splunk.table",
      "dataSources": {
        "primary": "ds_node_details_22"
      },
      "title": "Tunnel Interface Status",
      "description": "Per-interface operational state and description for every Tunnel* interface on each node (cisco.oper-status_info + cisco.description_info, Sub 40120/40121).\n\nUp = if-oper-state-ready; any other oper-state is Down.",
      "options": {
        "showInternalFields": false,
        "columnFormat": {
          "Status": {
            "rowBackgroundColors": "> table | seriesByName(\"Status\") | matchValue(tunnelStatusColorConfig)"
          }
        }
      },
      "context": {
        "tunnelStatusColorConfig": [
          {
            "match": "Up",
            "value": "#53A051"
          },
          {
            "match": "Down",
            "value": "#DC4E41"
          }
        ]
      }
    },
    "viz_node_details_9": {
      "type": "splunk.area",
      "dataSources": {
        "primary": "ds_node_details_9"
      },
      "title": "BGP Session Drops per Node",
      "description": "Per-interval delta of the cumulative connection.total-dropped counter (Sub 40114); the time bucket follows the selected time range.\n\nA non-zero spike marks a BGP session teardown/reset on that node.",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "New Session Drops / interval",
        "nullValueDisplay": "zero",
        "stackMode": "stacked"
      }
    },
    "viz_node_details_11": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_node_details_11"
      },
      "title": "EVPN RIB Churn per Node",
      "description": "Per-minute delta of the l2vpn-evpn bgp-table-version (Sub 40116). Each increment is a batch of EVPN route changes; sustained churn points to instability in the overlay.",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Table Version Delta / min",
        "nullValueDisplay": "zero"
      }
    },
    "viz_node_details_13": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_node_details_13"
      },
      "title": "NVE Peers Over Time",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "VTEP Peers",
        "nullValueDisplay": "connect"
      },
      "description": "Distinct VTEP peers per node over time (nve-peer-oper cp-vnis, 5m buckets).\n\nInventory-seeded so every device in the selected role appears — zero when no nve-peer-oper telemetry."
    },
    "viz_node_details_14": {
      "type": "splunk.area",
      "dataSources": {
        "primary": "ds_node_details_14"
      },
      "title": "VXLAN Throughput per Node — TX+RX Bytes/min (Sub 40115)",
      "description": "Per-minute delta of the per-NVE uc/mc input+output byte counters (Sub 40115, periodic 1 min). Approximates VXLAN data-plane throughput on each node's NVE interface. One NVE (nve1) per device, so series are keyed by node only (the numeric unit-number list key is not carried as a telemetry dimension).",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "VXLAN Bytes / min",
        "nullValueDisplay": "zero"
      }
    },
    "viz_node_details_15": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_node_details_15"
      },
      "title": "BUM vs Unicast TX Packets per Node — Packets/min (Sub 40115)",
      "description": "Per-minute delta of mc-output-packets (BUM/multicast) and uc-output-packets (unicast) from the NVE nve-oper-counters YANG path (Sub 40115).\n\nEach device produces two series: \"Leaf-XX (UC)\" and \"Leaf-XX (MC)\".\n\nIn a healthy EVPN fabric with ARP suppression, UC dominates; a rising MC line indicates BUM flooding (unknown-unicast, ARP suppression miss, or control-plane gap).\n\nNote: mc-output-packets is not yet populated on CAT9KV virtual platforms — MC lines will be 0 in lab; counters are expected to be non-zero on physical Cat9K hardware.",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "NVE TX Packets / min",
        "nullValueDisplay": "zero"
      }
    },
    "viz_node_details_16": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_node_details_16"
      },
      "title": "NVE Interface Packet Rate per Node — Packets/min over Time (Sub 40115)",
      "description": "Per-minute increment of the per-NVE unicast+multicast packet counters (uc-output + uc-input + mc-output, Sub 40115) charted over the selected time range, so each spike marks VXLAN packets crossing a node's NVE interface in that minute.\n\nCompanion to the VXLAN Throughput (bytes/min) chart above.\n\nFor a per-VNI top-talker breakout see the per-VNI throughput chart to the right (the numeric vni-id list key of nve-vni-oper-counters is now carried as a telemetry dimension).",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "NVE Packets / min",
        "nullValueDisplay": "zero"
      }
    },
    "viz_node_details_17": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_node_details_17"
      },
      "title": "Top VXLAN Segments by Throughput (Sub 40115)",
      "description": "Per-minute delta of the per-VNI uc/mc input+output byte counters (nve-vni-oper-counters, Sub 40115), broken out by the numeric vni-id list key now carried as a telemetry dimension by the fixed yanggrpcreceiver.\n\nEach series is one VXLAN segment (hostname + VNI ID), revealing which VNIs are the top data-plane talkers on each node — a breakout that was previously impossible when numeric keys were dropped.",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "VXLAN Bytes / min",
        "nullValueDisplay": "zero"
      }
    },
    "viz_node_details_19": {
      "type": "splunk.sankey",
      "dataSources": {
        "primary": "ds_node_details_19"
      },
      "title": "NVE Peer Adjacency (Device → VNI → VTEP Peer)",
      "description": "Unified VTEP adjacency and per-peer VNI mapping (latest snapshot within 24h — not bound to the time picker).\n\nSource: nve-peer-oper/peer-vni-group for per-peer VNI rows (vni dimension), with nve-peer-oper fallback for adjacency-only peers, enriched with evpn-inst/evpn-vlan/evpn-peer local↔remote VNI pairs when available.\n\nFlow: Device → VNI (L:local R:remote when EVPN peer binding exists; plain VNI from peer-vni-group otherwise) → VTEP peer (inventory loopback lookup).\n\nNote: L≠R flags a VNI mismatch; peers with no learned VNI show Device → VTEP only. Empty-state stub checks both peer-vni-group and nve-peer-oper adjacency.",
      "options": {
        "seriesColors": [
          "#1D6FA4",
          "#53A051",
          "#F8BE34",
          "#DC4E41",
          "#F1813F",
          "#6DB7C6"
        ]
      }
    },
    "viz_node_details_20": {
      "type": "splunk.sankey",
      "dataSources": {
        "primary": "ds_node_details_20"
      },
      "title": "EVPN VNI Binding — Control Plane",
      "description": "Control-plane binding from evpn-oper/evpn-inst/evpn-vlan (BGP EVPN).\n\nChain: Leaf → EVI (tenant) → L3VNI → L2VNI → L2 VLAN.\n\nCross-check vs the paired NVE Sankey:\n\nEVI should match VRF ; L3VNI, L2VNI, and L2 VLAN/NVE L2 VNI numbers should align.",
      "options": {
        "seriesColors": [
          "#1D6FA4",
          "#53A051",
          "#F8BE34",
          "#DC4E41",
          "#F1813F",
          "#6DB7C6"
        ]
      }
    },
    "viz_node_details_24": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_node_details_24"
      },
      "title": "L3 VNI (VRF) Count per Node",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "VRF Count",
        "nullValueDisplay": "connect"
      }
    },
    "viz_node_details_30": {
      "type": "splunk.sankey",
      "dataSources": {
        "primary": "ds_node_details_30"
      },
      "title": "EVPN VNI Binding — Data Plane (NVE)",
      "description": "Data-plane binding from nve-oper/nve-vni-oper (NVE programmed state).\n\nChain: Leaf → VRF → L3VNI → NVE L2 VNI → L2 VLAN (oper Up/Down).\n\nL3-only VNIs terminate at L3VNI.\n\nCross-check vs the control-plane Sankey for tenant name and VNI/VLAN alignment.",
      "options": {
        "seriesColors": [
          "#1D6FA4",
          "#53A051",
          "#F8BE34",
          "#DC4E41",
          "#F1813F",
          "#6DB7C6"
        ]
      }
    },
    "viz_node_details_31": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_node_details_31"
      },
      "title": "Tunnel Interfaces Up per Node Over Time",
      "description": "Operationally Up Tunnel* interface count per node (if-oper-state-ready, Sub 40120/40121, 5m buckets).\n\nInventory-seeded so every device in the selected role appears — zero when no tunnel telemetry.",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Tunnels Up",
        "nullValueDisplay": "zero"
      }
    }
  },
  "dataSources": {
    "ds_node_details_input0": {
      "type": "ds.search",
      "options": {
        "query": "| inputlookup evpn_device_inventory | stats count by site | fields site | sort site",
        "queryParameters": {
          "earliest": "0",
          "latest": "now"
        }
      },
      "name": "Site"
    },
    "ds_node_details_0": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.vni-oper-state_info\") AS _m WHERE `evpn_index` earliest=$timeRange.earliest$ span=1m \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-vni-oper\" BY \"cisco.node_id\", \"vni-id\", \"value\" | `evpn_lookup` | where site=\"$site$\" AND role=\"$role$\" | sort 0 - _time | dedup hostname, \"vni-id\" | eval down=if(value=\"nve-vni-state-down\",1,0) | stats sum(down) AS Down count AS Total | eval Up=Total-Down | eval vni_state=\"▲ \".Up.\"   ▼ \".Down | fields vni_state",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "NVE VNIs ▲ Up / ▼ Down"
    },
    "ds_node_details_1": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.negotiated-keepalive-timers.hold-time\") AS hold_time WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-bgp-oper:bgp-state-data/neighbors/neighbor\" BY \"cisco.node_id\", \"vrf-name\", \"neighbor-id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"$role$\" | stats count(eval(hold_time>0)) AS Up count(eval(hold_time==0)) AS Down | eval bgp_state=\"▲ \".Up.\"   ▼ \".Down | fields bgp_state",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "BGP Sessions ▲ Up / ▼ Down"
    },
    "ds_node_details_2": {
      "type": "ds.search",
      "options": {
        "query": "| inputlookup evpn_device_inventory | where site=\"$site$\" AND role=\"$role$\" | fields hostname | join type=left hostname [ | mstats latest(\"cisco.cp-vnis.\") AS cp_vnis WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-peer-oper\" BY \"cisco.node_id\", \"peer-addr\" | rename \"peer-addr\" AS peer_addr | `evpn_lookup` | where site=\"$site$\" AND role=\"$role$\" | stats dc(peer_addr) AS peers BY hostname ] | eval peers=coalesce(peers,0) | stats sum(peers) AS n | fields n",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "VTEP Tunnel Peers"
    },
    "ds_node_details_3": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.vni-type_info\") AS x WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-vni-oper\" BY \"cisco.node_id\", \"vni-id\", \"value\" | `evpn_lookup` | where site=\"$site$\" AND role=\"$role$\" AND value=\"nve-vni-type-l2\" | stats dc(\"vni-id\") AS n | fields n",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "Active L2 VNIs"
    },
    "ds_node_details_4": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.vni-type_info\") AS x WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-vni-oper\" BY \"cisco.node_id\", \"vni-id\", \"value\" | `evpn_lookup` | where site=\"$site$\" AND role=\"$role$\" AND value=\"nve-vni-type-l3\" | stats dc(\"vni-id\") AS n | fields n",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "Active VRFs / L3 VNIs"
    },
    "ds_node_details_5": {
      "type": "ds.search",
      "options": {
        "query": "| inputlookup evpn_device_inventory | where site=\"$site$\" AND role=\"$role$\" | dedup hostname | fields hostname | join type=left hostname [ | mstats count(\"cisco.l2cp-vni-num\") AS n WHERE `evpn_index` earliest=$timeRange.earliest$ span=1m \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper\" BY \"cisco.node_id\" | rename \"cisco.node_id\" AS hostname | stats max(_time) AS t_nve by hostname ] | join type=left hostname [ | mstats count(\"cisco.cp-vnis.\") AS n WHERE `evpn_index` earliest=$timeRange.earliest$ span=1m \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-peer-oper\" BY \"cisco.node_id\" | rename \"cisco.node_id\" AS hostname | stats max(_time) AS t_peer by hostname ] | join type=left hostname [ | mstats count(\"cisco.oper-status_info\") AS n WHERE `evpn_index` earliest=$timeRange.earliest$ span=1m \"cisco.encoding_path\"=\"Cisco-IOS-XE-interfaces-oper:interfaces/interface\" BY \"cisco.node_id\" | rename \"cisco.node_id\" AS hostname | stats max(_time) AS t_if by hostname ] | eval cutoff=relative_time(now(), \"-5m\") | eval silent=if(isnull(t_nve) OR t_nve<cutoff OR isnull(t_peer) OR t_peer<cutoff OR isnull(t_if) OR t_if<cutoff, 1, 0) | stats sum(silent) AS n",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "Silent Nodes (>5m)"
    },
    "ds_node_details_21": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.oper-status_info\") AS _m WHERE `evpn_index` earliest=$timeRange.earliest$ span=1m \"cisco.encoding_path\"=\"Cisco-IOS-XE-interfaces-oper:interfaces/interface\" BY \"cisco.node_id\", name, value | `evpn_lookup` | where site=\"$site$\" AND role=\"$role$\" | where like(name, \"Tunnel%\") | sort 0 - _time | dedup hostname, name | eval down=if(value!=\"if-oper-state-ready\",1,0) | stats sum(down) AS Down count AS Total | eval Up=Total-Down | eval tunnel_state=\"▲ \".Up.\"   ▼ \".Down | fields tunnel_state",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "Tunnel Interfaces ▲ Up / ▼ Down"
    },
    "ds_node_details_6": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.negotiated-keepalive-timers.hold-time\") AS hold_time WHERE `evpn_index` earliest=$timeRange.earliest$ span=30s BY \"cisco.node_id\", \"vrf-name\", \"neighbor-id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"$role$\" | eval established=if(hold_time>0, 1, 0) | stats sum(established) AS established by _time, hostname | eval established=round(established,0) | xyseries _time hostname established | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "BGP Established Sessions per Node"
    },
    "ds_node_details_7": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.l3cp-vni-num\") AS l3_vni_count WHERE `evpn_index` earliest=$timeRange.earliest$ span=5m \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper\" BY \"cisco.node_id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"$role$\" | stats last(l3_vni_count) AS l3_vni_count by _time, hostname | xyseries _time hostname l3_vni_count | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "L3 VNI (VRF) Count per Node"
    },
    "ds_node_details_8": {
      "type": "ds.search",
      "options": {
