      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.oper-status_info\") AS _m WHERE `evpn_index` earliest=$timeRange.earliest$ span=5m \"cisco.encoding_path\"=\"Cisco-IOS-XE-interfaces-oper:interfaces/interface\" BY \"cisco.node_id\", name, value | rename value AS oper_status | `evpn_lookup` | where site=\"$site$\" AND role=\"$role$\" | where like(name, \"Tunnel%\") | sort 0 - _time hostname name | dedup _time, hostname, name | eval up=if(oper_status=\"if-oper-state-ready\",1,0) | stats sum(up) AS tunnels_up by _time, hostname | append [ | inputlookup evpn_device_inventory | where site=\"$site$\" AND role=\"$role$\" | fields hostname | join type=left hostname [ | mstats latest(\"cisco.oper-status_info\") AS _m WHERE `evpn_index` earliest=$timeRange.earliest$ span=5m \"cisco.encoding_path\"=\"Cisco-IOS-XE-interfaces-oper:interfaces/interface\" BY \"cisco.node_id\", name, value | rename value AS oper_status | `evpn_lookup` | where site=\"$site$\" AND role=\"$role$\" | where like(name, \"Tunnel%\") | sort 0 - _time hostname name | dedup _time, hostname, name | eval up=if(oper_status=\"if-oper-state-ready\",1,0) | stats sum(up) AS tunnels_up by hostname ] | where isnull(tunnels_up) | eval tunnels_up=0 | join type=inner [ | mstats count(\"cisco.oper-status_info\") AS x WHERE `evpn_index` earliest=$timeRange.earliest$ span=5m BY \"cisco.node_id\" | stats count by _time ] | fields _time, hostname, tunnels_up ] | stats max(tunnels_up) AS tunnels_up by _time, hostname | xyseries _time hostname tunnels_up | fillnull value=0 | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "Tunnel Interfaces Up per Node Over Time"
    }
  },
